// ══════════════════════════════════════════════════════════════
// EXTENDED matchTopic FUNCTION
// ══════════════════════════════════════════════════════════════

function matchTopicExt(title, moduleSlug) {
  const t = n(title);
  const s = moduleSlug;

  // ── Python advanced ───────────────────────────────────────
  if (s === "python") {
    if (t.includes("fisier") || t.includes("i/o") || (t.includes("file") && !t.includes("profile"))) return TOPICS["python::files"];
    if (t.includes("generator") || t.includes("iterator")) return TOPICS["python::generators"];
    if (t.includes("concurenta") || t.includes("thread") || t.includes("multiprocessing") || t.includes("asyncio") || (t.includes("async") && !t.includes("javascript"))) return TOPICS["python::concurrency"];
    if (t.includes("regex") || t.includes("regular expression") || t.includes("expresii regulate")) return TOPICS["python::regex"];
    if (t.includes("test") || t.includes("pytest") || t.includes("debugg") || t.includes("profil")) return TOPICS["python::testing"];
    if (t.includes("libraria") || t.includes("stdlib") || t.includes("standard lib") || t.includes("unelte utile")) return TOPICS["python::stdlib"];
    if (t.includes("typing") || t.includes("dataclass") || t.includes("type hint") || t.includes("adnotare")) return TOPICS["python::typing"];
    if (t.includes("context manager") || t.includes("context managers") || t.includes("with ")) return TOPICS["python::context-mgr"];
    if (t.includes("modul") || t.includes("pachet") || t.includes("virtual env") || t.includes("pip") || t.includes("docker") || t.includes("sqlalchemy") || t.includes("click") || t.includes("cli ") || t.includes("composer")) return TOPICS["python::modules"];
    if (t.includes("modern") || t.includes("match ") || t.includes("pattern match") || t.includes("walrus") || t.includes("3.10") || t.includes("3.11") || t.includes("3.12")) return TOPICS["python::advanced-py"];
    if (t.includes("pandas") || t.includes("numpy") || t.includes("matplotlib") || t.includes("machine learning") || t.includes("data science") || t.includes("scikit") || t.includes("seaborn") || t.includes("calcul numeric") || t.includes("vizuali")) return TOPICS["python::data-science"];
    if (t.includes("oop avansat") || t.includes("design pattern") || t.includes("metaclas") || t.includes("magic method") || t.includes("descriptor")) return TOPICS["python::oop-advanced"];
    if (t.includes("proiect") || t.includes("todo") || t.includes("mini project") || t.includes("api complet") || t.includes("fastapi") || t.includes("web scrap") || t.includes("requests")) return TOPICS["python::project"];
    return null;
  }

  // ── JavaScript advanced ────────────────────────────────────
  if (s === "javascript") {
    if (t.includes("clase") || t.includes("class") || t.includes("oop") || t.includes("constructor")) return TOPICS["javascript::classes"];
    if (t.includes("dom") || t.includes("queryselector") || t.includes("event")) return TOPICS["javascript::dom"];
    if (t.includes("modul") || t.includes("import") || t.includes("export") || t.includes("esm") || t.includes("commonjs")) return TOPICS["javascript::modules"];
    if (t.includes("scope") || t.includes("closure") || t.includes("hoisting") || t.includes("iife")) return TOPICS["javascript::scope-closures"];
    if (t.includes("destructur") || t.includes("spread") || t.includes("rest")) return TOPICS["javascript::destructuring"];
    if (t.includes("regex") || t.includes("regular expression") || t.includes("expresii regulate")) return TOPICS["javascript::regex"];
    if (t.includes("generator") || t.includes("iterator")) return TOPICS["javascript::generators"];
    if (t.includes("eroare") || t.includes("error handling") || t.includes("try/catch") || t.includes("exception")) return TOPICS["javascript::error"];
    if (t.includes("typescript") || t.includes("type")) return TOPICS["javascript::typescript"];
    if (t.includes("test") || t.includes("jest")) return TOPICS["javascript::testing"];
    if (t.includes("pattern") || t.includes("design") || t.includes("functio") && t.includes("programm")) return TOPICS["javascript::patterns"];
    if (t.includes("web api") || t.includes("observer") || t.includes("worker") || t.includes("indexeddb") || t.includes("cache api")) return TOPICS["javascript::dom"];
    if (t.includes("websocket") || t.includes("sse") || t.includes("real-time")) return TOPICS["javascript::error"];
    if (t.includes("canvas") || t.includes("performance") || t.includes("modern") || t.includes("proxy") || t.includes("symbol")) return TOPICS["javascript::patterns"];
    return null;
  }

  // ── HTML advanced ──────────────────────────────────────────
  if (s === "html") {
    if (t.includes("text") || t.includes("formatare") || t.includes("tag-uri pentru") || t.includes("headings") || t.includes("paragraf")) return TOPICS["html::text-tags"];
    if (t.includes("link") || t.includes("imagine") || t.includes("a href") || t.includes("img")) return TOPICS["html::links-images"];
    if (t.includes("liste") || t.includes("list") && !t.includes("playlist")) return TOPICS["html::links-images"];
    if (t.includes("tabel") || t.includes("table")) return TOPICS["html::text-tags"];
    if (t.includes("semantic") || t.includes("article") || t.includes("section") || t.includes("nav") || t.includes("header") || t.includes("footer") || t.includes("landmark")) return TOPICS["html::semantics"];
    if (t.includes("audio") || t.includes("video") || t.includes("multimedia") || t.includes("iframe") || t.includes("embed") || t.includes("media")) return TOPICS["html::multimedia"];
    if (t.includes("accessib") || t.includes("a11y") || t.includes("aria") || t.includes("wai")) return TOPICS["html::accessibility"];
    if (t.includes("svg") || t.includes("scalable")) return TOPICS["html::advanced"];
    if (t.includes("canvas") || t.includes("template") || t.includes("web component") || t.includes("shadow dom") || t.includes("custom element") || t.includes("slot") || t.includes("pwa") || t.includes("service worker") || t.includes("manifest")) return TOPICS["html::advanced"];
    if (t.includes("meta") || t.includes("seo") || t.includes("microdata") || t.includes("performance") || t.includes("preload") || t.includes("lazy load") || t.includes("newsletter") || t.includes("email") || t.includes("internationali")) return TOPICS["html::meta-seo"];
    if (t.includes("drag") || t.includes("dialog") || t.includes("details") || t.includes("data attribute") || t.includes("progress")) return TOPICS["html::advanced"];
    return null;
  }

  // ── CSS advanced ───────────────────────────────────────────
  if (s === "css") {
    if (t.includes("box model") || t.includes("display") || t.includes("margin") || t.includes("padding") || t.includes("overflow")) return TOPICS["css::boxmodel"];
    if (t.includes("position") || t.includes("z-index") || t.includes("sticky") || t.includes("fixed") || t.includes("absolute")) return TOPICS["css::boxmodel"];
    if (t.includes("animat") || t.includes("tranzit") || t.includes("keyframe") || t.includes("transform")) return TOPICS["css::animations"];
    if (t.includes("variabil") || t.includes("custom propert") || t.includes("--")) return TOPICS["css::variables"];
    if (t.includes("pseudo") || t.includes("hover") || t.includes(":nth") || t.includes("::before") || t.includes("::after")) return TOPICS["css::pseudo"];
    if (t.includes("responsive") || t.includes("media quer") || t.includes("mobile") || t.includes("breakpoint") || t.includes("viewport") || t.includes("clamp")) return TOPICS["css::responsive"];
    if (t.includes("filter") || t.includes("backdrop") || t.includes("blend") || t.includes("clip-path") || t.includes("mask") || t.includes("object-fit")) return TOPICS["css::effects"];
    if (t.includes("scroll snap") || t.includes("scroll-driven")) return TOPICS["css::animations"];
    if (t.includes("modern") || t.includes(":has") || t.includes(":is") || t.includes(":where") || t.includes("@layer") || t.includes("cascade layer") || t.includes("nesting") || t.includes("@scope") || t.includes("container quer") || t.includes("subgrid") || t.includes("view trans") || t.includes("color level") || t.includes("houdini")) return TOPICS["css::modern-css"];
    if (t.includes("tipografi") || t.includes("font") || t.includes("text")) return TOPICS["css::variables"];
    if (t.includes("background") || t.includes("border") || t.includes("box-shadow") || t.includes("gradient")) return TOPICS["css::animations"];
    return null;
  }

  // ── React advanced ─────────────────────────────────────────
  if (s === "react") {
    if (t.includes("useeffect") || t.includes("ciclu") || t.includes("lifecycle") || t.includes("mount") || t.includes("cleanup")) return TOPICS["react::lifecycle"];
    if (t.includes("context") || t.includes("createcontext") || t.includes("state global")) return TOPICS["react::context"];
    if (t.includes("router") || t.includes("navigare") || t.includes("outlet") || t.includes("usenavigat") || t.includes("useparam")) return null; // handled by seed-quality
    if (t.includes("form") || t.includes("input") || t.includes("controlled") || t.includes("react hook form") || t.includes("zod")) return TOPICS["react::forms"];
    if (t.includes("memo") || t.includes("usememo") || t.includes("usecallback") || t.includes("performance") || t.includes("virtual") || t.includes("lazy") || t.includes("suspense")) return TOPICS["react::performance"];
    if (t.includes("portal") || t.includes("forwardref") || t.includes("compound") || t.includes("render prop") || t.includes("hoc") || t.includes("higher order") || t.includes("ref avansat")) return TOPICS["react::advanced"];
    if (t.includes("redux") || t.includes("zustand") || t.includes("state management") || t.includes("usereducer")) return TOPICS["react::state-management"];
    if (t.includes("query") || t.includes("swr") || t.includes("tanstack") || t.includes("server state")) return TOPICS["react::testing"];
    if (t.includes("test") || t.includes("vitest") || t.includes("testing library") || t.includes("storybook")) return TOPICS["react::testing"];
    if (t.includes("animati") || t.includes("framer") || t.includes("motion")) return TOPICS["react::performance"];
    if (t.includes("react 19") || t.includes("server component") || t.includes("use() hook") || t.includes("action")) return TOPICS["react::advanced"];
    if (t.includes("accesib") || t.includes("a11y") || t.includes("aria")) return TOPICS["react::testing"];
    if (t.includes("micro-frontend") || t.includes("react native") || t.includes("avansat")) return TOPICS["react::patterns"];
    return null;
  }

  // ── C advanced ─────────────────────────────────────────────
  if (s === "c") {
    if (t.includes("array") || t.includes("string") || t.includes("sir de")) return TOPICS["c::arrays-strings"];
    if (t.includes("struct") || t.includes("uniune") || t.includes("union") || t.includes("typedef")) return TOPICS["c::structs"];
    if (t.includes("fisier") || t.includes("file i/o") || t.includes("fopen") || t.includes("i/o")) return TOPICS["c::files"];
    if (t.includes("malloc") || t.includes("free") || t.includes("alocare din") || t.includes("memory") || t.includes("pointer") && t.includes("avansat")) return TOPICS["c::memory"];
    if (t.includes("preprocesor") || t.includes("macro") || t.includes("bitwise") || t.includes("compilare") || t.includes("linking") || t.includes("debug") || t.includes("gdb") || t.includes("pointer la functie")) return TOPICS["c::preprocessor-c"];
    if (t.includes("hash") || t.includes("arbore") || t.includes("lista inlantuita") || t.includes("stiva") || t.includes("coada") || t.includes("structuri de date")) return TOPICS["c::data-structures"];
    if (t.includes("socket") || t.includes("thread") || t.includes("signal") || t.includes("concurent") || t.includes("ipc")) return TOPICS["c::concurrency-c"];
    if (t.includes("sortare") || t.includes("cautare") || t.includes("algoritm") || t.includes("recursivitate") || t.includes("bfs") || t.includes("dfs")) return TOPICS["c::algorithms"];
    return null;
  }

  // ── SQL advanced ───────────────────────────────────────────
  if (s === "sql") {
    if (t.includes("join") && !t.includes("project")) return TOPICS["sql::joins"];
    if (t.includes("group by") || t.includes("having") || t.includes("agregh") || t.includes("count") || t.includes("sum(") || t.includes("avg(")) return TOPICS["sql::aggregate"];
    if (t.includes("subquer") || t.includes("cte") || t.includes("exists") || t.includes("corela")) return TOPICS["sql::subqueries"];
    if (t.includes("create table") || t.includes("alter table") || t.includes("ddl") || t.includes("index") || t.includes("constraint") || t.includes("foreign key") || t.includes("schema")) return TOPICS["sql::ddl"];
    if (t.includes("tranzact") || t.includes("commit") || t.includes("rollback") || t.includes("begin") || t.includes("savepoint") || t.includes("isolation") || t.includes("atomici") || t.includes("acid")) return TOPICS["sql::transactions"];
    if (t.includes("window") || t.includes("row_number") || t.includes("rank") || t.includes("ntile") || t.includes("lag") || t.includes("lead") || t.includes("stored proc") || t.includes("trigger") || t.includes("view")) return TOPICS["sql::aggregate"];
    return null;
  }

  return null;
}

// ══════════════════════════════════════════════════════════════
// MAIN
// ══════════════════════════════════════════════════════════════

const TARGET_MODULES = new Set([
  "python", "javascript", "html", "css", "react", "c", "sql"
]);

const DIFF_ORDER = { easy: 0, medium: 1, hard: 2 };

async function main() {
  const modules = await p.module.findMany({
    where: { slug: { in: [...TARGET_MODULES] } },
    include: {
      lessons: { include: { tasks: true }, orderBy: { order: "asc" } },
    },
    orderBy: { order: "asc" },
  });

  const lang = (slug) => MODULE_LANG[slug] || "javascript";

  let replaced = 0;
  let skipped = 0;

  for (const mod of modules) {
    console.log(`\nModul: ${mod.slug} (${mod.lessons.length} lecții)`);

    for (const lesson of mod.lessons) {
      const topic = matchTopicExt(lesson.title, mod.slug);

      if (!topic) {
        skipped++;
        continue;
      }

      // Șterge fillblanks + codings existente
      await p.task.deleteMany({
        where: { lessonId: lesson.id, type: { in: ["fillblank", "coding"] } },
      });

      // Reordonează quiz-urile 1-5 (easy→hard)
      const quizTasks = await p.task.findMany({
        where: { lessonId: lesson.id, type: "quiz" },
        orderBy: { number: "asc" },
      });

      const sorted = quizTasks
        .slice(0, 5)
        .sort((a, b) => (DIFF_ORDER[a.difficulty] ?? 1) - (DIFF_ORDER[b.difficulty] ?? 1));

      for (let i = 0; i < sorted.length; i++) {
        const t = sorted[i];
        const opts = t.options?.length ? [...t.options] : [];
        for (let j = opts.length - 1; j > 0; j--) {
          const k = Math.floor(Math.random() * (j + 1));
          [opts[j], opts[k]] = [opts[k], opts[j]];
        }
        await p.task.update({
          where: { id: t.id },
          data: { number: i + 1, options: opts },
        });
      }

      // Inserează fillblanks (6-10)
      let num = 6;
      for (const f of topic.fillblanks) {
        await p.task.create({
          data: {
            lessonId: lesson.id,
            number: num++,
            type: "fillblank",
            difficulty: f.difficulty,
            name: f.name,
            question: f.question,
            answer: f.answer.toString().trim(),
            explanation: f.explanation || null,
            options: [],
            language: lang(mod.slug),
          },
        });
      }

      // Inserează codings (11-15)
      for (const c of topic.codings) {
        await p.task.create({
          data: {
            lessonId: lesson.id,
            number: num++,
            type: "coding",
            difficulty: c.difficulty,
            name: c.name,
            question: c.question,
            answer: "",
            starterCode: c.starterCode,
            expectedOutput: (c.expectedOutput || "").trim(),
            options: [],
            language: c.language || lang(mod.slug),
          },
        });
      }

      replaced += topic.fillblanks.length + topic.codings.length;
    }
  }

  console.log(`\n${"=".repeat(50)}`);
  console.log(`Înlocuite: ${replaced} task-uri`);
  console.log(`Sărite:    ${skipped} lecții (deja cu content specific)`);
  console.log("=".repeat(50));
}

main()
  .catch(console.error)
  .finally(() => p.$disconnect());
